<?php $checks=['PHP 8.3+'=>version_compare(PHP_VERSION,'8.3','>='),'PDO'=>extension_loaded('pdo_mysql'),'GD'=>extension_loaded('gd'),'OpenSSL'=>extension_loaded('openssl'),'Uploads writable'=>is_writable(__DIR__.'/../uploads')];if($_SERVER['REQUEST_METHOD']==='POST'){require_once __DIR__.'/../config/db.php';$sql=file_get_contents(__DIR__.'/../database.sql');db()->exec($sql);$email=$_POST['email'];$pass=password_hash($_POST['password'],PASSWORD_DEFAULT);db()->prepare('insert into users(role_id,name,email,password_hash,status,created_at)values(2,"Administrator",?,?,"active",now())')->execute([$email,$pass]);echo 'Installed. Delete /install now.';exit;}?><h1>GiftVault Installer</h1><?php foreach($checks as $k=>$v)echo "<p>$k: ".($v?'OK':'FAIL').'</p>';?><form method="post"><input name="email" placeholder="Admin email"><input name="password" type="password" placeholder="Password"><button>Install</button></form>
